1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	type Step = QuoteStep;
14	
15	interface Scenario {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	}
19	
20	const BASE_PREMIUM: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const BLOCK_SIZE = 3;
31	const BLOCK_PREMIUM = 60;
32	
33	const FIRST_INSURANCE_SURCHARGE = 0.1;
34	const CURSE_SURCHARGE = 0.5;
35	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const PROCESSING_FEE = 5;
38	
39	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
40	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
41	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
42	
43	// A block applies only to a group of exactly BLOCK_SIZE alike components,
44	// priced at BLOCK_PREMIUM; any other count is priced individually.
45	const componentBasePremium = (count: number, perComponent: number): number => {
46	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
47	  return count * perComponent;
48	};
49	
50	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
51	
52	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
53	const isMainItem = (item: Item): boolean => !isComponent(item);
54	
55	const countByType = (items: Item[]): Record<string, number> => {
56	  const counts: Record<string, number> = {};
57	  for (const item of items) {
58	    counts[item.type] = (counts[item.type] ?? 0) + 1;
59	  }
60	  return counts;
61	};
62	
63	// A surcharge rate is an additive percentage applied on top of a base premium.
64	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
65	
66	// Item-specific surcharges are additive percentages of the item's base premium.
67	// First insurance applies to every item; the curse surcharge to cursed items.
68	const itemSurchargeRate = (item: Item): number => {
69	  const curse = item.cursed ? CURSE_SURCHARGE : 0;
70	  const highEnchantment =
71	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_SURCHARGE : 0;
72	  return FIRST_INSURANCE_SURCHARGE + curse + highEnchantment;
73	};
74	
75	const mainItemPremium = (item: Item): number =>
76	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
77	
78	const componentGroupPremium = (count: number, perComponent: number): number =>
79	  applySurcharge(componentBasePremium(count, perComponent), FIRST_INSURANCE_SURCHARGE);
80	
81	const itemsPremium = (items: Item[]): number => {
82	  const componentCounts = countByType(items.filter(isComponent));
83	
84	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
85	  const componentsPremium = sum(
86	    Object.entries(componentCounts).map(([type, count]) =>
87	      componentGroupPremium(count, BASE_PREMIUM[type]),
88	    ),
89	  );
90	
91	  return mainItemsPremium + componentsPremium;
92	};
93	
94	const quotePremium = (items: Item[]): number =>
95	  roundPremiumUp(itemsPremium(items) + PROCESSING_FEE);
96	
97	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
98	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
99	  return { results };
100	};
